327→    accountAgeDays = toNumber(accountResult.rows[0]?.account_age_days, 0);
328→  } catch (error) {
329→    if (!isMissingDbObjectError(error)) throw error;
330→  }
331→
332→  const totalResult = await query<{ total: number }>(
333→    `SELECT COUNT(*)::int AS total FROM point_events WHERE user_id = $1`,
334→    [userId],
335→  );
336→  const totalSubmissions = toInt(totalResult.rows[0]?.total, 0);
337→
338→  let priorFraudFlags = 0;
339→  try {
340→    const fraudResult = await query<{ total: number }>(
341→      `SELECT COUNT(*)::int AS total
342→       FROM fraud_audit_log
343→       WHERE user_id = $1
344→         AND action IN ('flagged', 'blocked')`,
345→      [userId],
346→    );
347→    priorFraudFlags = toInt(fraudResult.rows[0]?.total, 0);
348→  } catch (error) {
349→    if (!isMissingDbObjectError(error)) throw error;
350→  }
351→
352→  return { accountAgeDays, totalSubmissions, priorFraudFlags };
353→}
354→
355→async function getSelfEnrichmentStats(userId: string, pointId: string): Promise<{ recentSelfEnrichments: number; ownsPoint: boolean }> {
356→  const result = await query<{ recent_self_enrichments: number; owns_point: boolean }>(
357→    `SELECT
358→       COUNT(*) FILTER (
359→         WHERE event_type = 'ENRICH_EVENT'
360→           AND user_id = $1
361→           AND created_at > NOW() - INTERVAL '24 hours'
362→       )::int AS recent_self_enrichments,
363→       BOOL_OR(event_type = 'CREATE_EVENT' AND user_id = $1) AS owns_point
364→     FROM point_events
365→     WHERE point_id = $2`,
366→    [userId, pointId],
367→  );
368→  return {
369→    recentSelfEnrichments: toInt(result.rows[0]?.recent_self_enrichments, 0),
370→    ownsPoint: result.rows[0]?.owns_point === true,
371→  };
372→}
