 95→async function handleCronDispatch(url: URL): Promise<Response> {
 96→  const now = resolveCronDispatchInstant(url.searchParams.get("at"));
 97→  if (!now) {
 98→    return errorResponse("Invalid at timestamp. Use ISO-8601 UTC format.", 400);
 99→  }
100→
101→  const dateOverride = url.searchParams.get("date") ?? undefined;
102→  const schedule = getCronDispatchSchedule(now);
103→  const jobs: CronDispatchSummary["jobs"] = {
104→    weeklySnapshot: { due: schedule.weeklySnapshot, status: "skipped", message: "Not scheduled for this run" },
105→    monthlyRollup: { due: schedule.monthlyRollup, status: "skipped", message: "Not scheduled for this run" },
106→    dailyRoadSnapshot: { due: schedule.dailyRoadSnapshot, status: "skipped", message: "Not scheduled for this run" },
107→  };
108→
109→  let hasFailures = false;
110→
111→  if (schedule.weeklySnapshot) {
112→    try {
113→      jobs.weeklySnapshot = {
114→        due: true,
115→        status: "ok",
116→        message: "Weekly snapshot executed",
117→        result: await runWeeklySnapshotCron(dateOverride),
118→      };
119→    } catch (error) {
120→      hasFailures = true;
121→      jobs.weeklySnapshot = {
122→        due: true,
123→        status: "error",
124→        message: asErrorMessage(error),
125→      };
126→      console.error("Cron dispatch weekly snapshot failed:", error);
127→    }
128→  }
129→
130→  if (schedule.monthlyRollup) {
131→    try {
132→      jobs.monthlyRollup = {
133→        due: true,
134→        status: "ok",
135→        message: "Monthly rollup executed",
136→        result: await runMonthlyRollupCron(dateOverride),
137→      };
138→    } catch (error) {
139→      hasFailures = true;
140→      jobs.monthlyRollup = {
141→        due: true,
142→        status: "error",
143→        message: asErrorMessage(error),
144→      };
145→      console.error("Cron dispatch monthly rollup failed:", error);
146→    }
147→  }
148→
149→  if (schedule.dailyRoadSnapshot) {
150→    try {
151→      jobs.dailyRoadSnapshot = {
152→        due: true,
153→        status: "ok",
154→        message: "Daily road snapshot executed",
155→        result: await runDailyRoadSnapshotCron(dateOverride),
156→      };
157→    } catch (error) {
158→      hasFailures = true;
159→      jobs.dailyRoadSnapshot = {
160→        due: true,
161→        status: "error",
162→        message: asErrorMessage(error),
163→      };
164→      console.error("Cron dispatch daily road snapshot failed:", error);
165→    }
166→  }
167→
168→  const summary: CronDispatchSummary = {
169→    evaluatedAtUtc: now.toISOString(),
170→    schedule,
171→    executedAnyJob: schedule.weeklySnapshot || schedule.monthlyRollup || schedule.dailyRoadSnapshot,
172→    hasFailures,
173→    jobs,
174→  };
175→
176→  return jsonResponse(summary, { status: hasFailures ? 500 : 200 });
177→}
