714→export async function POST(request: Request): Promise<Response> {
715→  const auth = await requireUser(request);
716→  if (!auth) return errorResponse("Unauthorized", 401);
717→  const authContext = toSubmissionAuthContext(auth);
718→  const isAdminUser = authContext?.isAdmin === true;
719→
720→  let rawBody: unknown;
721→  try {
722→    rawBody = await request.json();
723→  } catch {
724→    return errorResponse("Invalid JSON body", 400);
725→  }
726→
727→  const validation = submissionInputSchema.safeParse(rawBody);
728→  if (!validation.success) {
729→    return errorResponse(validation.error.issues[0]?.message ?? "Invalid submission payload", 400);
730→  }
731→
732→  const body = validation.data as SubmissionInput;
733→  const category = normalizeCategory(body?.category as string | undefined);
734→  if (!category) {
735→    return errorResponse("Invalid category", 400);
736→  }
737→
738→  const userProfile = await getUserProfile(auth.id);
739→  if (userProfile?.suspendedUntil && new Date(userProfile.suspendedUntil).getTime() > Date.now()) {
740→    return errorResponse("Your account is temporarily suspended from submitting data", 403);
741→  }
742→
743→  const userRate = await consumeRateLimit({
744→    route: "POST /api/submissions",
745→    key: auth.id,
746→    windowSeconds: 60 * 60,
747→    max: SUBMISSION_RATE_LIMIT_PER_HOUR,
748→    request,
749→    userId: auth.id,
750→  });
751→  if (!userRate.allowed) {
752→    return jsonResponse(
753→      { error: "Submission rate limit exceeded. Please try again later.", code: "rate_limited" },
754→      { status: 429, headers: { "retry-after": String(userRate.retryAfterSeconds) } },
755→    );
756→  }
757→
758→  const requestIp = currentRequestIp(request);
759→  if (requestIp) {
760→    const ipRate = await consumeRateLimit({
761→      route: "POST /api/submissions:ip",
762→      key: requestIp,
763→      windowSeconds: 60 * 60,
764→      max: SUBMISSION_IP_RATE_LIMIT_PER_HOUR,
765→      request,
766→      userId: auth.id,
767→    });
768→    if (!ipRate.allowed) {
769→      return jsonResponse(
770→        { error: "Submission rate limit exceeded for this network. Please try again later.", code: "rate_limited" },
771→        { status: 429, headers: { "retry-after": String(ipRate.retryAfterSeconds) } },
772→      );
773→    }
774→  }
775→
776→  const eventType = normalizeEventType(body?.eventType);
777→  const submissionBody = body as unknown as Record<string, unknown>;
778→  const dedupDecision = normalizeDedupDecision(submissionBody?.dedupDecision);
779→  const dedupTargetPointId =
780→    typeof submissionBody?.dedupTargetPointId === "string"
781→      ? (submissionBody.dedupTargetPointId as string).trim()
782→      : "";
783→  const location = parseLocation(body?.location);
784→  const consentStatus = normalizeConsentStatus(body.consentStatus) ?? "not_required";
785→  const consentRecordedAt = body.consentRecordedAt ?? new Date().toISOString();
786→  let details = normalizeEnrichPayload(
787→    category,
788→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
789→  );
790→  if (consentStatus === "refused_pii_only") {
791→    details = {
792→      ...stripPiiDetails(details),
793→      consentStatus,
794→      consentRecordedAt,
795→    };
796→  }
797→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
798→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
799→  if (clientDevice) {
800→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
801→    details.clientDevice = clientDevice;
802→  } else if ("clientDevice" in details) {
803→    delete details.clientDevice;
804→  }
805→  const gpsIntegrity = sanitizeGpsIntegrity(body.gpsIntegrity);
806→  if (gpsIntegrity) {
807→    details.gpsIntegrity = gpsIntegrity;
808→  }
809→  if (consentStatus) {
810→    details.consentStatus = consentStatus;
811→    details.consentRecordedAt = consentRecordedAt;
812→  }
813→
814→  const imageBase64 = body?.imageBase64 as string | undefined;
815→  if (!imageBase64) return errorResponse("Photo is required", 400);
816→  const parsedPhoto = parseImagePayload(imageBase64);
817→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
818→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
819→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
820→  }
821→
822→  const ipInfo = await getIpInfo(request);
823→  const ipLocation = ipInfo?.location ?? null;
824→  const ipHash = ipInfo?.ip ? hashIpIdentifier(ipInfo.ip) : null;
825→  const clientExif = (body as unknown as Record<string, unknown>)?.clientExif as ClientExifData | null | undefined;
826→  const clientPhotoEvidenceSha256 =
827→    typeof body.photoEvidenceSha256 === "string" && body.photoEvidenceSha256.trim() ? body.photoEvidenceSha256.trim() : null;
828→  let photoLocation: SubmissionLocation | null = null;
829→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null;
830→
831→  try {
832→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer, {
833→      source: "upload_buffer",
834→      mime: parsedPhoto.mime,
835→      ext: parsedPhoto.ext,
836→      byteLength: parsedPhoto.imageBuffer.byteLength,
837→    });
838→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
839→    if (primaryPhotoMetadata.gps) {
840→      photoLocation = primaryPhotoMetadata.gps;
841→      if (location) {
842→        const distance = haversineKm(location, photoLocation);
843→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
844→      }
845→      if (ipLocation) {
846→        const distance = haversineKm(ipLocation, photoLocation);
847→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
848→      }
849→    } else if (!location && !ipLocation) {
850→      return errorResponse("Photo is missing GPS metadata", 400);
851→    }
852→  } catch {
853→    primaryPhotoMetadata = {
854→      gps: null,
855→      capturedAt: null,
856→      deviceMake: null,
857→      deviceModel: null,
858→      exifStatus: "parse_error",
859→      exifReason: `Unexpected EXIF extraction failure (mime=${parsedPhoto.mime}; ext=${parsedPhoto.ext}; bytes=${parsedPhoto.imageBuffer.byteLength})`,
860→      exifSource: "upload_buffer",
861→    };
862→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
863→    if (!primaryPhotoMetadata.gps && !location && !ipLocation) {
864→      return errorResponse("Unable to read photo GPS metadata", 400);
865→    }
866→    if (primaryPhotoMetadata.gps) {
867→      photoLocation = primaryPhotoMetadata.gps;
868→    }
869→  }
870→
871→  const finalLocation = photoLocation ?? location ?? ipLocation;
872→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
873→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
874→    return errorResponse(
875→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
876→      400,
877→    );
878→  }
879→
880→  const idempotencyKey = trimString(request.headers.get("x-idempotency-key"), 160);
881→  if (idempotencyKey) {
882→    const requestHash = hashIdempotencyPayload(body);
883→    const reservation = await reserveIdempotencyKey({
884→      userId: auth.id,
885→      idempotencyKey,
886→      requestHash,
887→    });
888→    if (reservation.status === "conflict") {
889→      await logSecurityEvent({
890→        eventType: "idempotency_conflict",
891→        userId: auth.id,
892→        request,
893→        details: { idempotencyKey },
894→      });
895→      return errorResponse("This idempotency key was already used for a different submission", 409, {
896→        code: "idempotency_conflict",
897→      });
898→    }
899→    if (reservation.status === "replay" && reservation.eventId) {
900→      const replayEvent = (await buildReadableEvents()).find((event) => event.id === reservation.eventId);
901→      if (replayEvent) {
902→        return jsonResponse(replayEvent, { status: reservation.responseStatus });
903→      }
904→    }
905→  }
906→
907→  try {
908→    const existingEvents = await buildReadableEvents();
909→    const projectedExisting = projectPointsFromEvents(existingEvents);
910→    let pointId = typeof body.pointId === "string" && body.pointId.trim()
911→      ? body.pointId.trim()
912→      : generatePointId(category, finalLocation.latitude, finalLocation.longitude);
913→    let effectiveEventType: PointEventType = eventType;
914→    let allowGaplessEnrich = false;
915→    const dedupResult = eventType === "CREATE_EVENT"
916→      ? buildDedupCandidates(category, finalLocation, details, projectedExisting)
917→      : null;
918→
919→    if (eventType === "CREATE_EVENT" && dedupDecision === "use_existing") {
920→      const chosenPointId = dedupTargetPointId || dedupResult?.bestCandidatePointId;
921→      if (!chosenPointId) {
922→        return errorResponse("dedupTargetPointId is required when dedupDecision=use_existing", 400);
923→      }
924→      const candidate = dedupResult?.candidates.find((item) => item.pointId === chosenPointId);
925→      if (!candidate) {
