  const resetForAnotherCapture = () => {
    if (photoPreview?.startsWith('blob:')) {
      URL.revokeObjectURL(photoPreview);
    }
    setSubmitted(false);
    setPhotoPreview(null);
    setPhotoFile(null);
    setDraftImageBase64(null);
    setDraftClientExif(null);
    setLocation(null);
    setManualLatitude('');
    setManualLongitude('');
    setPhotoError('');
    setLocationError('');
    setErrorMessage('');
    setSyncMessage('');
    setPendingPayload(null);
    setSelectedDedupPointId('');
    setDedupCheck(null);
    setConsentStatus('not_required');
    setSiteName('');
    setOpeningHours('');
    setProviders([]);
    setMerchantId('');
    setPaymentMethods([]);
    setFuelTypes([]);
    setPriceValue('');
    setAdvertiserBrand('');
    setRoadName('');
    setStoreyCount('');
    setEstimatedUnits('');
    setEnrichValues({});
    setEnrichTouched({});
    setEnrichMultiRaw({});
  };

  const handleBackPress = () => {
    if (isBatchMode) {
      onBatchExit?.();
    }
    onBack();
  };

  const verticalIcon = <VerticalIcon name={VERTICALS[vertical]?.icon ?? 'pill'} size={18} />;

