  return (
    <div className="flex flex-col h-full bg-[#f9fafb]">
      <div className="pt-6 px-6">
        <div className="flex items-center justify-between mb-3">
          <button onClick={handleBackPress} className="p-1 -ml-1 text-gray-500">
            <ArrowLeft size={24} />
