                    <span className={`text-[9px] font-bold uppercase tracking-widest ${step.done ? 'text-[#4c7c59]' : 'text-gray-300'}`}>
                      {step.label}
                    </span>
                  </div>
                  {i < steps.length - 1 && <div className={`flex-1 h-px ${steps[i].done ? 'bg-[#4c7c59]' : 'bg-gray-200'}`} />}
                </React.Fragment>
              ))}
            </div>
