    isVpn: boolean;
    isTor: boolean;
  } | null;
  hasSecondaryPhoto: boolean;
}

export interface SubmissionRiskEvaluation {
  shouldBlock: boolean;
  blockCode: string | null;
  blockReason: string | null;
  imageHash: string;
  contentHash: string;
