  xpAction: XpAction;
  velocity: {
    user15m: number;
    device15m: number | null;
    ip15m: number | null;
    deviceDistinctUsers15m: number | null;
    ipDistinctUsers15m: number | null;
  };
  impossibleTravelSpeedKmh: number | null;
