239→        <button className="p-2 text-gray-400 absolute right-2">
240→          <Share2 size={20} />
241→        </button>
242→      </div>
243→
244→      <div className="p-4 space-y-6">
245→        {adminMode ? (
246→          <div className="flex items-center justify-between py-2">
247→            <div className="flex items-center space-x-3">
248→              <div className="w-12 h-12 rounded-full border-2 border-white shadow bg-[#e7eef4] overflow-hidden">
249→                <img src="https://picsum.photos/seed/kofi/300/300" alt={t('avatar', 'avatar')} className="w-full h-full object-cover" />
250→              </div>
