133→function toNumber(input: unknown, fallback = 0): number {
134→  if (typeof input === "number" && Number.isFinite(input)) return input;
135→  if (typeof input === "string") {
136→    const parsed = Number(input);
137→    if (Number.isFinite(parsed)) return parsed;
138→  }
139→  return fallback;
140→}
141→
142→function toInt(input: unknown, fallback = 0): number {
143→  return Math.max(0, Math.round(toNumber(input, fallback)));
144→}
145→
146→function normalizeText(input: unknown): string {
147→  if (typeof input !== "string") return "";
148→  return input.trim().toLowerCase();
149→}
150→
151→function isMissingDbObjectError(error: unknown): boolean {
152→  const pg = error as { code?: unknown; message?: unknown } | null;
153→  const code = typeof pg?.code === "string" ? pg.code : "";
154→  if (code === "42P01" || code === "42703") return true;
155→  const message = typeof pg?.message === "string" ? pg.message.toLowerCase() : "";
156→  return message.includes("does not exist") || message.includes("undefined column") || message.includes("undefined table");
157→}
158→
159→function isUniqueViolationError(error: unknown): boolean {
160→  const pg = error as { code?: unknown } | null;
161→  return pg?.code === "23505";
162→}
