164→function stableSort(value: unknown): unknown {
165→  if (Array.isArray(value)) return value.map(stableSort);
166→  if (!value || typeof value !== "object") return value;
167→  const entries = Object.entries(value as Record<string, unknown>)
168→    .filter(([, v]) => v !== undefined)
169→    .sort(([a], [b]) => a.localeCompare(b));
170→  const out: Record<string, unknown> = {};
171→  for (const [key, nextValue] of entries) {
172→    out[key] = stableSort(nextValue);
173→  }
174→  return out;
175→}
