194→export async function computePerceptualHash(imageBuffer: Buffer): Promise<string | null> {
195→  try {
196→    const sharp = (await import("sharp")).default;
197→    const { data } = await sharp(imageBuffer)
198→      .resize(8, 8, { fit: "fill" })
199→      .grayscale()
200→      .raw()
201→      .toBuffer({ resolveWithObject: true });
202→    const pixels = Array.from(data);
203→    const mean = pixels.reduce((sum, v) => sum + v, 0) / pixels.length;
204→    let hash = "";
205→    for (const pixel of pixels) {
206→      hash += pixel >= mean ? "1" : "0";
207→    }
208→    // Convert binary string to hex
209→    let hex = "";
210→    for (let i = 0; i < hash.length; i += 4) {
211→      hex += parseInt(hash.slice(i, i + 4), 2).toString(16);
212→    }
213→    return hex;
214→  } catch {
215→    return null;
216→  }
217→}
