232→export function computeEventContentHash(input: {
233→  pointId: string;
234→  category: SubmissionCategory;
235→  eventType: PointEventType;
236→  location: SubmissionLocation;
237→  details: SubmissionDetails;
238→}): string {
239→  const stablePayload = {
240→    pointId: input.pointId,
241→    category: input.category,
242→    eventType: input.eventType,
243→    latitude: Number(input.location.latitude.toFixed(6)),
244→    longitude: Number(input.location.longitude.toFixed(6)),
245→    details: sanitizeDetailsForContentHash(input.details),
246→  };
247→  return hashText(JSON.stringify(stableSort(stablePayload)));
248→}
