444→function evaluateFieldPlausibility(category: SubmissionCategory, details: SubmissionDetails): { block: string | null; flags: string[] } {
445→  if (category !== "fuel_station") return { block: null, flags: [] };
446→  const flags: string[] = [];
447→
448→  const pricesByFuel = details.pricesByFuel;
449→  if (!pricesByFuel || typeof pricesByFuel !== "object") return { block: null, flags };
450→
451→  for (const [fuelTypeRaw, value] of Object.entries(pricesByFuel as Record<string, unknown>)) {
452→    const fuelType = normalizeText(fuelTypeRaw);
453→    const numeric = toNumber(value, NaN);
454→    if (!Number.isFinite(numeric)) continue;
455→    if (numeric <= 0 || numeric > 10_000) {
456→      return { block: `invalid_fuel_price_${fuelType || "unknown"}`, flags };
457→    }
458→    const range = FUEL_PRICE_RANGE_XAF[fuelType];
459→    if (!range) continue;
460→    if (numeric < range.min * 0.5 || numeric > range.max * 2) {
461→      flags.push("implausible_fuel_price");
462→    }
463→  }
464→
465→  return { block: null, flags: Array.from(new Set(flags)) };
466→}
