487→export async function evaluateSubmissionRisk(input: SubmissionRiskInput): Promise<SubmissionRiskEvaluation> {
488→  const imageHash = computeImageSha256(input.imageBuffer);
489→  const contentHash = computeEventContentHash({
490→    pointId: input.pointId,
491→    category: input.category,
492→    eventType: input.eventType,
493→    location: input.finalLocation,
494→    details: input.details,
495→  });
496→
497→  const [
498→    userVelocity,
499→    lastSubmission,
500→    duplicateMatches,
501→    userRiskStats,
502→    selfEnrichment,
503→    deviceVelocity,
504→    ipVelocity,
505→  ] = await Promise.all([
506→    getUserVelocityCount(input.userId),
507→    getLastSubmissionByUser(input.userId),
508→    getDuplicateImageMatches(imageHash),
509→    getUserRiskStats(input.userId),
510→    getSelfEnrichmentStats(input.userId, input.pointId),
511→    input.clientDevice?.deviceId ? getDeviceVelocityStats(input.clientDevice.deviceId) : Promise.resolve({ count: 0, distinctUsers: 0 }),
512→    input.ipHash ? getIpVelocityStats(input.ipHash) : Promise.resolve({ count: 0, distinctUsers: 0 }),
513→  ]);
514→
515→  const reviewFlags = new Set<string>();
516→  const blockingCodes = new Set<string>();
517→
518→  let locationRisk = 0;
519→  if (!input.submissionLocation) locationRisk += 15;
520→  if (!input.photoMetadata.gps) locationRisk += 20;
521→  if (!input.ipLocation) locationRisk += 10;
522→
523→  if (input.submissionLocation && input.photoMetadata.gps) {
524→    const distance = haversineKm(input.submissionLocation, input.photoMetadata.gps);
525→    if (distance > 1) {
526→      locationRisk += 40;
527→      reviewFlags.add("gps_mismatch");
528→    } else if (distance > 0.5) {
529→      locationRisk += 15;
530→      reviewFlags.add("gps_marginal_match");
531→    }
532→  }
533→
534→  if (input.ipLocation && input.photoMetadata.gps) {
535→    const ipDistance = haversineKm(input.ipLocation, input.photoMetadata.gps);
536→    if (ipDistance > 50) {
537→      locationRisk += 30;
538→      reviewFlags.add("ip_photo_mismatch");
539→    } else if (ipDistance > 20) {
540→      locationRisk += 10;
541→      reviewFlags.add("ip_photo_marginal_match");
542→    }
543→  }
544→
545→  if (input.ipReputation?.isDatacenter || input.ipReputation?.isVpn) {
546→    locationRisk += 10;
547→    reviewFlags.add("suspicious_ip_org");
548→  }
549→  if (input.ipReputation?.isTor) {
550→    locationRisk += 40;
551→    blockingCodes.add("tor_exit_ip");
552→  }
553→  // 6A: GPS validation integration
554→  const gpsValidation = validateGps({
555→    submissionLocation: input.submissionLocation,
556→    photoLocation: input.photoMetadata.gps,
557→    gpsIntegrity: input.gpsIntegrity,
558→  });
559→  if (gpsValidation.score < 50) {
560→    locationRisk += Math.round((100 - gpsValidation.score) * 0.3);
561→    for (const flag of gpsValidation.flags) reviewFlags.add(`gps_${flag}`);
562→  }
563→  if (gpsValidation.mockDetected) {
564→    reviewFlags.add("gps_mock_detected");
565→  }
566→  locationRisk = Math.min(100, locationRisk);
567→
568→  let photoRisk = 0;
569→  if (!input.photoMetadata.gps) photoRisk += 15;
570→  if (!input.photoMetadata.capturedAt) photoRisk += 10;
571→  if (!input.photoMetadata.deviceMake) photoRisk += 10;
572→  if (!input.photoMetadata.deviceModel) photoRisk += 10;
573→
574→  const duplicateForDifferentPoint = duplicateMatches.some((row) => row.pointId !== input.pointId);
575→  if (duplicateForDifferentPoint) {
576→    photoRisk += 80;
577→    blockingCodes.add("duplicate_photo");
578→  }
579→  const duplicateForSamePoint = duplicateMatches.some((row) => row.pointId === input.pointId);
580→  if (duplicateForSamePoint) {
581→    reviewFlags.add("duplicate_photo_same_point");
582→    photoRisk += 25;
583→  }
584→
585→  // 6B: Photo freshness scoring
586→  const freshnessScore = computePhotoFreshnessScore(
587→    input.photoMetadata.capturedAt,
588→    new Date().toISOString(),
589→  );
590→  if (freshnessScore < 30) {
591→    photoRisk += 20;
592→    reviewFlags.add("stale_photo");
593→  } else if (freshnessScore < 60) {
594→    photoRisk += 10;
595→    reviewFlags.add("aging_photo");
596→  }
597→
598→  // 6C: Screenshot & editing detection
599→  const manipulation = detectPhotoManipulation({
600→    gps: input.photoMetadata.gps,
601→    capturedAt: input.photoMetadata.capturedAt,
602→    deviceMake: input.photoMetadata.deviceMake,
603→    deviceModel: input.photoMetadata.deviceModel,
604→    software: input.photoExifExtra?.software ?? null,
605→    imageWidth: input.photoExifExtra?.imageWidth ?? null,
606→    imageHeight: input.photoExifExtra?.imageHeight ?? null,
607→    fileSize: input.photoExifExtra?.fileSize ?? null,
608→  });
609→  if (manipulation.isScreenshot) {
610→    photoRisk += 25;
611→    reviewFlags.add("screenshot_detected");
612→  }
613→  if (manipulation.isEdited) {
614→    photoRisk += 20;
615→    reviewFlags.add("editing_software_detected");
616→  }
617→  if (manipulation.isDownloaded) {
618→    photoRisk += 15;
619→    reviewFlags.add("downloaded_image_detected");
620→  }
621→
622→  if (input.clientDevice?.isLowEnd && photoRisk > 0 && photoRisk <= 35) {
623→    photoRisk = Math.max(0, photoRisk - 10);
624→  }
625→  photoRisk = Math.min(100, photoRisk);
626→
627→  let temporalRisk = 0;
628→  if (userVelocity >= USER_VELOCITY_BLOCK_THRESHOLD) {
629→    temporalRisk += 60;
630→    blockingCodes.add("velocity_limit");
631→  } else if (userVelocity >= USER_VELOCITY_FLAG_THRESHOLD) {
632→    temporalRisk += 30;
633→    reviewFlags.add("high_user_velocity");
634→  } else if (userVelocity >= 3) {
635→    temporalRisk += 10;
636→  }
637→
638→  if (deviceVelocity.count >= DEVICE_VELOCITY_FLAG_THRESHOLD) {
639→    temporalRisk += 15;
640→    reviewFlags.add("high_device_velocity");
641→  }
642→  if (deviceVelocity.distinctUsers >= 2) {
643→    temporalRisk += 10;
644→    reviewFlags.add("shared_device");
645→  }
646→
647→  if (ipVelocity.count >= IP_VELOCITY_FLAG_THRESHOLD) {
648→    temporalRisk += 10;
649→    reviewFlags.add("high_ip_velocity");
650→  }
651→  if (ipVelocity.distinctUsers >= 3) {
652→    temporalRisk += 10;
653→    reviewFlags.add("shared_ip");
654→  }
655→
656→  let impossibleTravelSpeedKmh: number | null = null;
657→  if (lastSubmission) {
658→    const distanceKm = haversineKm(lastSubmission.location, input.finalLocation);
659→    const elapsedHours =
660→      (Date.now() - new Date(lastSubmission.createdAt).getTime()) / (1000 * 60 * 60);
661→    if (elapsedHours > 0) {
662→      impossibleTravelSpeedKmh = distanceKm / elapsedHours;
663→      if (impossibleTravelSpeedKmh > IMPOSSIBLE_TRAVEL_BLOCK_KMH) {
664→        temporalRisk += 50;
665→        blockingCodes.add("impossible_travel");
666→      } else if (impossibleTravelSpeedKmh > IMPOSSIBLE_TRAVEL_FLAG_KMH) {
667→        temporalRisk += 25;
668→        reviewFlags.add("impossible_travel");
669→      }
670→    }
671→  }
672→  temporalRisk = Math.min(100, temporalRisk);
673→
674→  let userRisk = 0;
675→  if (userRiskStats.accountAgeDays < 1) userRisk += 25;
676→  else if (userRiskStats.accountAgeDays < 7) userRisk += 15;
677→  else if (userRiskStats.accountAgeDays < 30) userRisk += 5;
678→
679→  if (userRiskStats.totalSubmissions === 0) userRisk += 15;
680→  else if (userRiskStats.totalSubmissions < 5) userRisk += 8;
681→
682→  if (userRiskStats.priorFraudFlags >= 5) {
683→    userRisk += 40;
684→    reviewFlags.add("repeat_fraud_pattern");
685→  } else if (userRiskStats.priorFraudFlags >= 1) {
686→    userRisk += 20;
687→    reviewFlags.add("historical_fraud_flags");
688→  }
689→  userRisk = Math.min(100, userRisk);
690→
691→  let behavioralRisk = 0;
692→  if (input.eventType === "ENRICH_EVENT" && selfEnrichment.ownsPoint) {
693→    behavioralRisk += 20;
694→    reviewFlags.add("self_enrichment");
695→    if (selfEnrichment.recentSelfEnrichments >= 3) {
696→      behavioralRisk += 25;
697→      reviewFlags.add("self_enrichment_loop");
698→    }
699→    if (selfEnrichment.recentSelfEnrichments >= 5) {
700→      blockingCodes.add("velocity_limit");
701→    }
702→  }
703→
704→  const plausibility = evaluateFieldPlausibility(input.category, input.details);
705→  if (plausibility.block) {
706→    blockingCodes.add(plausibility.block);
707→  }
708→  for (const flag of plausibility.flags) reviewFlags.add(flag);
709→
710→  const exifTrustScore = computeExifTrustScore({
711→    gps: input.photoMetadata.gps,
712→    capturedAt: input.photoMetadata.capturedAt,
713→    deviceMake: input.photoMetadata.deviceMake,
714→    deviceModel: input.photoMetadata.deviceModel,
715→    isLowEnd: input.clientDevice?.isLowEnd === true,
716→  });
717→
718→  if (exifTrustScore < EXIF_TRUST_FLAG_THRESHOLD) {
719→    reviewFlags.add("low_exif_trust");
720→    behavioralRisk += exifTrustScore < 40 ? 25 : 10;
721→    if (exifTrustScore < 40 && !input.hasSecondaryPhoto) {
722→      reviewFlags.add("secondary_photo_recommended");
723→    }
724→  }
725→
726→  behavioralRisk = Math.min(100, behavioralRisk);
727→
728→  const riskComponents: RiskComponents = {
729→    locationRisk,
730→    photoRisk,
731→    temporalRisk,
732→    userRisk,
733→    behavioralRisk,
734→  };
735→
736→  const riskScore = buildRiskScore(riskComponents);
737→  const shouldReview = reviewFlags.size > 0 || riskScore >= REVIEW_RISK_THRESHOLD;
738→
739→  if (input.isAdmin && blockingCodes.size > 0) {
740→    for (const code of blockingCodes) {
741→      reviewFlags.add(`admin_bypass_${code}`);
742→    }
743→    reviewFlags.add("admin_bypass");
744→    blockingCodes.clear();
745→  }
746→
747→  // 6D: Perceptual hash duplicate detection
748→  try {
749→    const perceptualHash = await computePerceptualHash(input.imageBuffer);
750→    if (perceptualHash) {
751→      const perceptualMatches = await getPerceptualHashMatches(perceptualHash);
752→      const nearDuplicate = perceptualMatches.some((row) => row.pointId !== input.pointId);
753→      if (nearDuplicate) {
754→        photoRisk = Math.min(100, photoRisk + 30);
755→        reviewFlags.add("perceptual_near_duplicate");
756→      }
757→    }
758→  } catch {
759→    // Perceptual hashing is best-effort; don't block submissions if sharp fails
760→  }
761→
762→  const firstBlockCode = blockingCodes.values().next().value ?? null;
763→  const block = firstBlockCode ? blockDetailsForCode(firstBlockCode) : null;
764→
765→  // 6E: XP escrow logic
766→  let xpAction: XpAction;
767→  if (firstBlockCode) {
768→    xpAction = "deny";
769→  } else if (riskScore > 75) {
770→    xpAction = "deny";
771→  } else if (riskScore > 50) {
772→    xpAction = "escrow";
773→  } else {
774→    xpAction = "award";
775→  }
776→
777→  return {
778→    shouldBlock: Boolean(firstBlockCode),
779→    blockCode: firstBlockCode,
780→    blockReason: block?.reason ?? null,
781→    imageHash,
782→    contentHash,
783→    reviewStatus: shouldReview ? "pending_review" : "auto_approved",
784→    reviewFlags: Array.from(reviewFlags),
785→    riskScore,
786→    exifTrustScore,
787→    xpAction,
788→    velocity: {
789→      user15m: userVelocity,
790→      device15m: input.clientDevice?.deviceId ? deviceVelocity.count : null,
791→      ip15m: input.ipHash ? ipVelocity.count : null,
792→      deviceDistinctUsers15m: input.clientDevice?.deviceId ? deviceVelocity.distinctUsers : null,
793→      ipDistinctUsers15m: input.ipHash ? ipVelocity.distinctUsers : null,
794→    },
795→    impossibleTravelSpeedKmh,
796→    riskComponents,
797→  };
798→}
