800→async function persistContentHash(eventId: string, contentHash: string): Promise<void> {
801→  try {
802→    await query(
803→      `UPDATE point_events
804→       SET content_hash = $2
805→       WHERE id = $1::uuid`,
806→      [eventId, contentHash],
807→    );
808→  } catch (error) {
809→    if (isMissingDbObjectError(error)) return;
810→    throw error;
811→  }
